mapper.update:
UPDATE task_notification 
SET is_read = 1 
WHERE notificationid = #{notificationid}

UPDATE task_notification 
SET is_read = 1 
WHERE roomid = #{roomid}

mapper.delete:
DELETE FROM task_notification 
WHERE roomid = #{roomid} 
AND notificationid NOT IN (
    SELECT notificationid FROM (
        SELECT notificationid 
        FROM task_notification 
        WHERE roomid = #{roomid}
        ORDER BY createtime DESC 
        LIMIT #{keepCount}
    ) AS recent_notifications
)
